<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const pv=parseFloat(document.getElementById('emp-valor').value);const juros=parseFloat(document.getElementById('emp-juros').value)/100;const meses=parseInt(document.getElementById('emp-meses').value,10);clearError();if(isNaN(pv)||isNaN(juros)||isNaN(meses)||pv<=0||juros<0||meses<=0){showError('Preencha valor, juros e prazo com números válidos.');return;}const parcela=juros===0?pv/meses:(pv*juros)/(1-Math.pow(1+juros,-meses));const total=parcela*meses;document.getElementById('emp-parcela').textContent='R$ '+fmtBRL(parcela);document.getElementById('emp-total').textContent='R$ '+fmtBRL(total);document.getElementById('tool-detail').textContent='Simulação com prestação constante para apoio de análise.';showResult('tool-result');}function clearTool(){['emp-valor','emp-juros','emp-meses'].forEach(id=>document.getElementById(id).value='');['emp-parcela','emp-total'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule o empréstimo antes de copiar o resultado.');return;}copyToClipboard('Parcela: '+document.getElementById('emp-parcela').textContent+'\nTotal pago: '+document.getElementById('emp-total').textContent,button);}
</script>
